INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'd32e215b-4f7e-4f67-bdf7-69a2ee77f0fd',
  '00000000-0000-0000-0000-000000000001',
  $escape$Jest E2E with jest-puppeteer — Testing Critical Auth Flows Without Flakiness$escape$,
  $escape$E2E tests in Jest run through `jest-puppeteer`, which exposes a global `page` (Puppeteer's Page object) and a `browser` instance to every test file. The preset handles browser lifecycle — you never call `puppeteer.launch()` yourself.

The rule for critical-path E2E is ruthless scope: test auth, onboarding, and the one action that is the core of your product. Everything else belongs in unit or integration tests. Flaky E2E suites die because they test too much.

Use `beforeAll` (not `beforeEach`) for navigation when tests in a suite share the same starting URL — saves one full page load per test. Use `waitForNavigation({ waitUntil: 'networkidle0' })` after form submits instead of arbitrary `page.waitForTimeout()` delays; it ties the assertion to actual network quiescence rather than a guess.

For auth specifically, avoid seeding test users through the UI. Use a `globalSetup` script in `jest.config.js` to hit your API directly and create the fixture user once before the suite runs. This keeps the E2E test focused on the browser flow, not setup noise.$escape$,
  $escape$// jest.config.js → preset: 'jest-puppeteer', globalSetup: './setup/create-test-user.js'

describe('Auth critical path', () => {
  beforeAll(async () => {
    await page.goto('http://localhost:3000/login');
  });

  it('signs in and redirects to dashboard', async () => {
    await page.type('[data-testid="email"]', 'fixture@test.com');
    await page.type('[data-testid="password"]', 'Fixture123!');
    await page.click('[data-testid="submit"]');
    await page.waitForNavigation({ waitUntil: 'networkidle0' });
    expect(page.url()).toContain('/dashboard');
  });
});$escape$,
  $escape$javascript$escape$,
