INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '088ed04e-8394-4d9b-9a1d-b2c64fc1cfb3',
  '00000000-0000-0000-0000-000000000001',
  $escape$Jest + MSW — API Mocking That Survives Refactors$escape$,
  $escape$`jest.mock('axios')` couples tests to implementation details — swap axios for fetch and every mock breaks. MSW intercepts at the network layer in Jest's Node environment via `msw/node`, making mocks transport-agnostic.

The rule: use MSW when testing code that makes HTTP calls. Use `jest.fn()` for pure business logic, event handlers, or module-level side effects.

Set up a shared server in a setup file referenced by `setupFilesAfterFramework` in `jest.config.ts`, then override per-test with `server.use()` for error paths — 401s, 500s, malformed payloads. Call `server.resetHandlers()` in `afterEach` so per-test overrides don't bleed.

`onUnhandledRequest: 'error'` is your safety net: any unmocked endpoint throws, keeping your test surface explicit. Without it, requests silently fall through in Jest's jsdom or node env — or worse, hit a real service in CI.

Avoid `jest.mock('./api')` for integration-style component tests — you're asserting against a lie. MSW keeps the full fetch path real while controlling only the response, so refactoring the HTTP layer doesn't invalidate your tests.$escape$,
  $escape$// setup/server.ts
import { setupServer } from 'msw/node'
import { http, HttpResponse } from 'msw'

export const server = setupServer(
  http.get('/api/user/:id', () => HttpResponse.json({ id: 1, name: 'Ada' }))
)

beforeAll(() => server.listen({ onUnhandledRequest: 'error' }))
afterEach(() => server.resetHandlers())
afterAll(() => server.close())

// user.test.ts
test('surfaces 404 from API', async () => {
  server.use(http.get('/api/user/:id', () => new HttpResponse(null, { status: 404 })))
  await expect(fetchUser(99)).rejects.toThrow('Not Found')
})$escape$,
