INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'e621546c-d228-4b61-9b72-cbc684e11252',
  '00000000-0000-0000-0000-000000000001',
  $escape$Jest to Vitest — Drop-in Migration with Vite-Native Speed$escape$,
  $escape$Vitest runs your existing Jest suite with near-zero config changes. It uses the same `describe`, `it`, `expect`, `beforeEach`, and `vi` (a drop-in for `jest`) globals, so most test files migrate by just updating imports. The real win is speed: Vitest shares Vite's module graph, meaning HMR-aware test reruns skip re-transforming unchanged modules entirely — something Jest's `--watchAll` can't match.

The sharpest difference is in-source testing. You can colocate tests inside the source file itself using `if (import.meta.vitest)` guards, which tree-shakes to nothing in production builds. No separate `__tests__` directories needed for small utility functions.

For Jest users, the migration checklist is short: replace `jest.fn()` with `vi.fn()`, swap `jest.mock()` with `vi.mock()`, and set `globals: true` in `vitest.config.ts` to avoid adding explicit imports. Coverage still uses `@vitest/coverage-v8` or `istanbul`, same reporters. If your project already uses Vite, there's no reason to keep Jest.$escape$,
  $escape$// vitest.config.ts
import { defineConfig } from 'vitest/config';

export default defineConfig({
  test: {
    globals: true,       // exposes describe/it/expect without imports
    environment: 'jsdom',
    coverage: { provider: 'v8' },
  },
});

// utils/math.ts — in-source test (tree-shaken in prod)
export const add = (a: number, b: number) => a + b;

if (import.meta.vitest) {
  const { it, expect } = import.meta.vitest;
  it('adds two numbers', () => expect(add(2, 3)).toBe(5));
}$escape$,
