INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '65c1505d-79de-435e-a778-69950bff8ec6',
  '00000000-0000-0000-0000-000000000001',
  $escape$Jest + Playwright — Multi-Browser, Trace Viewer, and Network Interception$escape$,
  $escape$jest-playwright-preset exposes `page`, `context`, and `browser` globals in every Jest test, letting you tap into Playwright's full API without ceremony.

For multi-browser coverage, set `browsers: ['chromium', 'firefox', 'webkit']` inside `testEnvironmentOptions` in `jest.config.js` — Jest runs each spec file once per browser, reporting failures per-browser label.

Network interception via `page.route()` is the cleanest way to stub flaky APIs in Jest integration tests. Call it before navigation; Playwright intercepts at the network layer — not the JS layer — so fetch, XHR, and service workers are all caught. Use `route.fulfill()` for mocked responses or `route.abort()` to simulate offline conditions.

For CI failures, wrap test bodies with `context.tracing.start({ screenshots: true, snapshots: true })` and `context.tracing.stop({ path: 'trace.zip' })`. Open the artifact with `npx playwright show-trace trace.zip` to replay every action with DOM snapshots and a full network waterfall — indispensable when a cross-browser assertion fails only on WebKit in CI.

Pair with `--testPathPattern` and `BROWSER=firefox` to isolate a single browser locally.$escape$,
  $escape$// jest.config.js
module.exports = {
  preset: 'jest-playwright-preset',
  testEnvironmentOptions: {
    browsers: ['chromium', 'firefox', 'webkit'],
  },
}

// users.test.js
test('renders empty state when API returns no users', async () => {
  await page.route('**/api/users', route =>
    route.fulfill({ status: 200, contentType: 'application/json', body: JSON.stringify([]) })
  )
  await context.tracing.start({ screenshots: true, snapshots: true })
  await page.goto('http://localhost:3000/users')
  await expect(page.locator('[data-testid="empty-state"]')).toBeVisible()
  await context.tracing.stop({ path: `traces/${browserName}-trace.zip` })
})$escape$,
  $escape$javascript$escape$,
