INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'ed9c94c3-ef11-43e3-ab0c-b0ceec2b6e01',
  '00000000-0000-0000-0000-000000000001',
  $escape$Jest Component Tests — Intercepting Network Requests Without cy.intercept$escape$,
  $escape$Jest has no built-in network interception layer like cy.intercept, but pairing it with MSW (Mock Service Worker) gives you the same declarative request stubbing inside component tests. Set up a msw server in your Jest globalSetup, then use server.use() inside individual tests to override handlers per-scenario — without touching the component or mocking fetch directly.

Jest's jsdom environment renders the component tree, while MSW intercepts at the service worker level (via node integration in Jest), meaning your actual fetch/axios calls fire and get intercepted transparently. This catches bugs that jest.spyOn(global, 'fetch') misses: serialization issues, base URL mismatches, and header composition.

For component testing mode specifically, configure testEnvironment to jsdom in jest.config.ts and use @testing-library/react's render. Unlike Cypress component mode, Jest mounts in-process — no browser binary, sub-100ms per test. Combine with userEvent.setup() for realistic interaction sequences before asserting on the stubbed network response.$escape$,
  $escape$// jest.setup.ts
import { server } from './mocks/server';
beforeAll(() => server.listen({ onUnhandledRequest: 'error' }));
afterEach(() => server.resetHandlers());
afterAll(() => server.close());

// component.test.tsx
import { http, HttpResponse } from 'msw';
import { render, screen } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import { UserProfile } from './UserProfile';

it('shows error state on 401', async () => {
  server.use(
    http.get('/api/profile', () => HttpResponse.json({ error: 'Unauthorized' }, { status: 401 }))
  );
  render(<UserProfile />);
  expect(await screen.findByText('Unauthorized')).toBeInTheDocument();
});$escape$,
